      // \u0446\u0432\u0435\u0442: \u0433\u043B\u0443\u0431\u043E\u043A\u0430\u044F \u2194 \u043C\u0435\u043B\u043A\u0430\u044F \u0432 \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u043C \u043F\u043E \u043A\u0440\u0443\u043F\u043D\u043E\u0439 \u0437\u044B\u0431\u0438 (\u0440\u044F\u0431\u044C \u043F\u043E\u0434\u043C\u0435\u0448\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0441\u043B\u0430\u0431\u043E)
